// ============================================================================
// SECTION 1: VALIDATE INPUT — MODE-AWARE
// Detects whether this is a session chat, dashboard chat, or general chat
// ============================================================================

const webhookData = $input.first().json;
const body = webhookData.body || webhookData;

// UUID validation regex
const uuidRegex =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// ============================================================================
// EXTRACT PARAMETERS
// ============================================================================

const userId = body.userId || null;
const sessionId = body.sessionId || null;
const bidId = body.bidId || "";
const message = body.message || "";
const viewerRole = body.viewerRole || "customer";
const companyId = body.companyId || body.viewerCompanyId || "";
const conversationHistory = body.conversationHistory || [];

// Dashboard-specific data (sent when context === 'dashboard')
const dashboardData = body.dashboardData || null;
const requestContext = body.context || "";

// ============================================================================
// MODE DETECTION
// ============================================================================

let chatMode = "session"; // default

if (sessionId && uuidRegex.test(sessionId)) {
  chatMode = "session";
} else if (dashboardData && dashboardData.userInfo) {
  chatMode = "dashboard";
} else {
  chatMode = "general";
}

// ============================================================================
// VALIDATION
// ============================================================================

// User ID always required
if (!userId) {
  throw new Error(
    "User authentication required. User must be logged in to use CLARENCE.",
  );
}

if (!uuidRegex.test(userId)) {
  throw new Error("Invalid user ID format. Please log in again.");
}

// Session ID only required for session mode
if (chatMode === "session" && !sessionId) {
  throw new Error("Session ID is required for session-based CLARENCE chat.");
}

if (chatMode === "session" && !uuidRegex.test(sessionId)) {
  throw new Error("Invalid session ID format.");
}

// Message always required
if (!message || message.trim() === "") {
  throw new Error("Message content is required.");
}

// Validate viewer role for session mode
if (chatMode === "session" && !["customer", "provider"].includes(viewerRole)) {
  throw new Error('viewerRole must be "customer" or "provider".');
}

// ============================================================================
// PREPARE OUTPUT
// ============================================================================

console.log("=== CLARENCE CHAT REQUEST ===");
console.log("Mode:", chatMode);
console.log("User:", userId);
console.log("Session:", sessionId || "(none - " + chatMode + " mode)");
console.log("Bid:", bidId || "(none)");
console.log("Role:", viewerRole);
console.log("Message length:", message.length);
if (dashboardData) {
  console.log(
    "Dashboard data: company=" + (dashboardData.userInfo?.company || "unknown"),
  );
  console.log(
    "Dashboard data: contracts=" + (dashboardData.totalContracts || 0),
  );
}

return {
  // Chat mode flag — used by all downstream nodes
  chatMode: chatMode,

  // For context builder (session mode only)
  sessionId: sessionId,
  bidId: bidId,
  viewerRole: viewerRole,
  viewerUserId: userId,
  viewerCompanyId: companyId,
  touchpointType: "chat",
  touchpointContext: {
    userMessage: message,
  },

  // Dashboard data (dashboard mode only)
  dashboardData: dashboardData,

  // Keep original data for later use
  original: {
    userId: userId,
    sessionId: sessionId,
    bidId: bidId,
    message: message,
    conversationHistory: conversationHistory,
    timestamp: new Date().toISOString(),
    chatMode: chatMode,
  },
};

