// ============================================================================
// SECTION 3: PROCESS CLAUDE RESPONSE — MODE-AWARE
// Handles response for both session and dashboard/general modes
// ============================================================================

const claudeResponse = $input.first().json;

// Determine which prompt builder was used
// In session mode, data comes through Build Session Prompt
// In dashboard mode, data comes through Build Dashboard Prompt
let promptData;
let chatMode;

try {
  promptData = $("Build Session Prompt").first().json;
  chatMode = "session";
} catch (e) {
  try {
    promptData = $("Build Dashboard Prompt").first().json;
    chatMode = promptData.chatMode || "dashboard";
  } catch (e2) {
    throw new Error("Could not find prompt data from either path");
  }
}

const ctx = promptData.context; // null for dashboard mode
const original = promptData.original;

// ============================================================================
// EXTRACT RESPONSE TEXT
// ============================================================================

let responseText = "";

if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
  const textBlock = claudeResponse.content.find(
    (block) => block.type === "text",
  );
  responseText = textBlock?.text || "";
} else if (claudeResponse.text) {
  responseText = claudeResponse.text;
} else if (typeof claudeResponse === "string") {
  responseText = claudeResponse;
}

if (!responseText) {
  console.log(
    "Claude response structure:",
    JSON.stringify(claudeResponse, null, 2),
  );
  responseText =
    "I apologise, but I was unable to generate a response. Please try again.";
}

// ============================================================================
// EXTRACT DISCOVERED DATA (session mode only)
// ============================================================================

const discoveredData = {};
const dataPattern = /\[DATA:\s*([^,]+),\s*([^\]]+)\]/g;
let match;
while ((match = dataPattern.exec(responseText)) !== null) {
  const category = match[1].trim();
  const value = match[2].trim();
  if (!discoveredData[category]) {
    discoveredData[category] = [];
  }
  discoveredData[category].push(value);
}

// Clean response (remove DATA markers)
const cleanResponse = responseText.replace(dataPattern, "").trim();

// ============================================================================
// BUILD CONVERSATION HISTORY
// ============================================================================

const previousHistory = original.conversationHistory || [];
const updatedHistory = [
  ...previousHistory,
  {
    role: "user",
    content: original.message,
    timestamp: original.timestamp,
  },
  {
    role: "assistant",
    content: cleanResponse,
    timestamp: new Date().toISOString(),
  },
];

// ============================================================================
// PREPARE STORAGE DATA (mode-aware)
// ============================================================================

let postgresData = null;

if (chatMode === "session" && ctx) {
  // Session mode: save to conversation_sessions
  postgresData = {
    user_id: original.userId,
    session_id: original.sessionId,
    conversation_history: JSON.stringify(updatedHistory),
    discovered_data: JSON.stringify(discoveredData),
    current_phase: ctx.session.currentPhase,
  };
}
// Dashboard/General mode: postgresData stays null (skip save)

console.log("=== CLAUDE RESPONSE PROCESSED ===");
console.log("Mode:", chatMode);
console.log("Response length:", cleanResponse.length);
console.log("Will save to DB:", postgresData !== null);
console.log("Model used:", claudeResponse.model || "unknown");
console.log("Stop reason:", claudeResponse.stop_reason || "unknown");

return {
  // Response data
  cleanResponse: cleanResponse,
  discoveredData: discoveredData,

  // Mode flag
  chatMode: chatMode,

  // For storage (null for dashboard mode)
  postgres: postgresData,

  // Pass through
  context: ctx,
  original: original,
  updatedHistory: updatedHistory,
  dashboardMeta: promptData.dashboardMeta || null,

  // API metadata
  apiMetadata: {
    model: claudeResponse.model,
    stopReason: claudeResponse.stop_reason,
    inputTokens: claudeResponse.usage?.input_tokens,
    outputTokens: claudeResponse.usage?.output_tokens,
  },
};

// ============================================================================
// SECTION 4: PREPARE FINAL RESPONSE — MODE-AWARE
// Returns consistent shape for frontend regardless of mode
// Fixes: overallAlignment → leverageBalance reference
// ============================================================================

const processedData = $("Process Response").first().json;
const chatMode = processedData.chatMode;
const ctx = processedData.context;
const original = processedData.original;

// ============================================================================
// SESSION MODE RESPONSE
// ============================================================================

if (chatMode === "session" && ctx) {
  return {
    success: true,
    response: processedData.cleanResponse,

    // Session info
    sessionId: original.sessionId,
    userId: original.userId,
    bidId: original.bidId || null,

    // Phase and alignment from live context
    currentPhase: ctx.session.currentPhase,
    alignmentScore: ctx.positions.alignmentPercentage,

    // Leverage data — FIXED: use leverageBalance instead of overallAlignment
    leverage: {
      customer: ctx.leverage.tracker.customer,
      provider: ctx.leverage.tracker.provider,
      balance: ctx.leverage.leverageBalance,
    },

    // Position summary
    positions: {
      total: ctx.positions.total,
      agreed: ctx.positions.agreed,
      disputed: ctx.positions.disputed,
      alignmentPercentage: ctx.positions.alignmentPercentage,
    },

    // Chat mode indicator
    chatMode: "session",

    // No artifact for chat
    artifact: null,
    shouldGenerateArtifact: false,

    // Metadata
    timestamp: new Date().toISOString(),
    contextBuildTime: processedData.buildTime || 0,

    debug: {
      viewerRole: ctx.viewer.role,
      viewerCompany: ctx.viewer.company,
      hasPlaybook: !!ctx.playbook,
      isTraining: ctx.mode.isTraining,
      biggestGapCount: ctx.positions.biggestGaps?.length || 0,
    },
  };
}

// ============================================================================
// DASHBOARD / GENERAL MODE RESPONSE
// ============================================================================

const dashMeta = processedData.dashboardMeta || {};

return {
  success: true,
  response: processedData.cleanResponse,

  // No session info
  sessionId: null,
  userId: original.userId,
  bidId: null,

  // No phase/alignment data
  currentPhase: null,
  alignmentScore: null,

  // No leverage data
  leverage: null,
  positions: null,

  // Chat mode indicator
  chatMode: chatMode,

  // No artifact
  artifact: null,
  shouldGenerateArtifact: false,

  // Metadata
  timestamp: new Date().toISOString(),
  contextBuildTime: 0,

  debug: {
    chatMode: chatMode,
    userName: dashMeta.userName || "unknown",
    companyName: dashMeta.companyName || "unknown",
    contractTypes: dashMeta.contractTypes || [],
  },
};

// ============================================================================
// SECTION 2A: BUILD SESSION PROMPT FROM UNIFIED CONTEXT
// Version: 2.0 — Role Matrix Integration + Audit Fixes
// Used when chatMode === 'session' (user is inside a contract session)
//
// CHANGES FROM V1:
// - Added ROLE_LABELS mapping for contract-type-aware party names
// - Added role context section to system prompt
// - Enhanced legal expertise framing (Tier 2)
// - Added position scale orientation guidance
// - Improved viewer anchoring with role labels
// - All existing audit fixes (position labels, terminology) preserved
// ============================================================================

const contextResult = $("Build Context").first().json;
const originalData = $("Validate Input").first().json.original;

// Validate context was built successfully
if (!contextResult.success || !contextResult.context) {
  throw new Error("Context builder returned invalid data");
}

const ctx = contextResult.context;

// ============================================================================
// SECTION: ROLE MATRIX — CONTRACT TYPE ROLE LABELS
// Maps contractTypeKey to proper party labels (Protected Party / Providing Party)
// Position 10 = Maximum protection for Protected Party
// Position 1  = Maximum flexibility for Providing Party
// ============================================================================

const ROLE_LABELS = {
  service_agreement: { protected: "Customer", providing: "Provider" },
  it_outsourcing: { protected: "Customer", providing: "Provider" },
  bpo_agreement: { protected: "Customer", providing: "Provider" },
  managed_services: { protected: "Customer", providing: "Provider" },
  saas_agreement: { protected: "Subscriber", providing: "Provider" },
  software_license: { protected: "Licensee", providing: "Licensor" },
  loan_agreement: { protected: "Borrower", providing: "Lender" },
  lease_agreement: { protected: "Tenant", providing: "Landlord" },
  employment_contract: { protected: "Employee", providing: "Employer" },
  nda_one_way: { protected: "Disclosing Party", providing: "Receiving Party" },
  nda_mutual: { protected: "Party A", providing: "Party B" },
  sales_agreement: { protected: "Buyer", providing: "Seller" },
  purchase_agreement: { protected: "Buyer", providing: "Seller" },
  construction_contract: { protected: "Client", providing: "Contractor" },
  consultancy_agreement: { protected: "Client", providing: "Consultant" },
  agency_agreement: { protected: "Principal", providing: "Agent" },
  distribution_agreement: { protected: "Distributor", providing: "Supplier" },
  franchise_agreement: { protected: "Franchisee", providing: "Franchisor" },
  insurance_policy: { protected: "Policyholder", providing: "Insurer" },
  maintenance_agreement: {
    protected: "Customer",
    providing: "Service Provider",
  },
};

// ============================================================================
// SECTION: DERIVE ROLE CONTEXT
// Uses contractTypeKey + initiatorPartyRole from session to determine
// who is the protected party and who is the providing party
// ============================================================================

// Check for pre-computed roleContext from the API (canonical Role Matrix source)
const passedRoleContext = originalData.roleContext || null;

const contractTypeKey = ctx.session.contractTypeKey || null;
const initiatorPartyRole = ctx.session.initiatorPartyRole || null;

// Get role labels — prefer passed roleContext, then local map, then defaults
const roleLabels = passedRoleContext ? {
  protected: passedRoleContext.protectedPartyLabel,
  providing: passedRoleContext.providingPartyLabel,
} : (ROLE_LABELS[contractTypeKey] || {
  protected: "Customer",
  providing: "Provider",
});

// Determine which label applies to the viewer
let userRoleLabel = "";
let otherRoleLabel = "";

if (passedRoleContext) {
  // Use pre-computed labels from the API — canonical Role Matrix source
  userRoleLabel = passedRoleContext.userRoleLabel;
  otherRoleLabel = passedRoleContext.counterpartyRoleLabel;
} else if (contractTypeKey && initiatorPartyRole) {
  // Fallback: derive from local ROLE_LABELS map
  if (ctx.viewer.role === "customer") {
    userRoleLabel = roleLabels[initiatorPartyRole] || roleLabels.protected;
    otherRoleLabel =
      initiatorPartyRole === "protected"
        ? roleLabels.providing
        : roleLabels.protected;
  } else {
    const respondentRole =
      initiatorPartyRole === "protected" ? "providing" : "protected";
    userRoleLabel = roleLabels[respondentRole] || roleLabels.providing;
    otherRoleLabel = roleLabels[initiatorPartyRole] || roleLabels.protected;
  }
} else {
  // Final fallback: no role data at all
  userRoleLabel = ctx.viewer.role === "customer" ? "Customer" : "Provider";
  otherRoleLabel = ctx.viewer.role === "customer" ? "Provider" : "Customer";
}

// ============================================================================
// SECTION: HELPER FUNCTIONS
// ============================================================================

function getPositionLabel(position, label1, label5, label10) {
  if (!label1 && !label5 && !label10) return null;
  if (position <= 2) return label1 || null;
  if (position <= 4)
    return label1 && label5
      ? `between ${label1} and ${label5}`
      : label1 || label5 || null;
  if (position === 5) return label5 || null;
  if (position <= 7)
    return label5 && label10
      ? `between ${label5} and ${label10}`
      : label5 || label10 || null;
  return label10 || null;
}

function getClauseGoverns(clauseName) {
  const governsMap = {
    "Payment Terms": "when and how payments are made",
    "Liability Cap": "maximum financial exposure for each party",
    "Termination Rights": "how and when parties can exit the contract",
    "IP Ownership":
      "who owns intellectual property created during the contract",
    "Data Protection": "how personal and sensitive data is handled",
    "Service Levels": "performance standards and remedies for failure",
    Indemnification: "who bears the cost of specific losses or claims",
    Confidentiality: "protection of sensitive business information",
    "Force Majeure": "rights when extraordinary events prevent performance",
    "Dispute Resolution": "how disagreements are resolved",
    "Change Control": "how contract modifications are managed",
    Insurance: "required coverage and risk transfer",
  };
  for (const [key, value] of Object.entries(governsMap)) {
    if (clauseName && clauseName.toLowerCase().includes(key.toLowerCase()))
      return value;
  }
  return "contract terms and obligations";
}

// ============================================================================
// SECTION: DETERMINE VIEWER CONTEXT
// ============================================================================

const isCustomerViewer = ctx.viewer.role === "customer";
const userPartyName = isCustomerViewer
  ? ctx.parties.customer.companyName
  : ctx.parties.provider.companyName;
const otherPartyName = isCustomerViewer
  ? ctx.parties.provider.companyName
  : ctx.parties.customer.companyName;
const userLeverage = isCustomerViewer
  ? ctx.leverage.tracker.customer
  : ctx.leverage.tracker.provider;
const otherLeverage = isCustomerViewer
  ? ctx.leverage.tracker.provider
  : ctx.leverage.tracker.customer;

// ============================================================================
// SECTION: BUILD SYSTEM PROMPT
// ============================================================================

const systemPrompt = `# CLARENCE System Prompt

You are CLARENCE (Contract Legal Alignment & Regulatory Efficiency Negotiation & Collaboration Engine), The Honest Broker — a professional contract mediator trusted by all parties.

## YOUR LEGAL EXPERTISE

You are an expert mediator with deep expertise in:
- Commercial contract law across major jurisdictions (UK, US, EU, Middle East, APAC)
- Business Process Outsourcing (BPO) agreements and IT outsourcing
- Service level agreements and performance management frameworks
- Liability allocation, indemnification, and risk management
- Data protection, GDPR, and cross-border data transfer regulations
- Employment law considerations in outsourcing (TUPE, ARD)
- Intellectual property rights in service delivery contexts
- Dispute resolution and termination frameworks

When users ask general legal questions (not specific to their contract), draw on your full legal expertise to provide authoritative, nuanced guidance. Always note that you are providing legal information, not legal advice, and recommend consulting a qualified lawyer for specific situations.

## CRITICAL: WHO YOU ARE SPEAKING TO

YOU ARE SPEAKING TO: ${userPartyName} (${ctx.viewer.role})
Their contract role: ${userRoleLabel}

The other party is: ${otherPartyName}
Their contract role: ${otherRoleLabel}

- ALWAYS use "you/your" when referring to ${userPartyName}
- ALWAYS use "${otherPartyName}" or "the ${otherRoleLabel}" when referring to the other party
- YOUR leverage is ${userLeverage}% (this is ${userPartyName}'s negotiating power)
- ${otherPartyName}'s leverage is ${otherLeverage}%
- NEVER confuse whose leverage is whose

## CONTRACT ROLE CONTEXT
${
  contractTypeKey
    ? `
This is a ${ctx.session.contractType || contractTypeKey.replace(/_/g, " ")}.
In this contract type:
- The ${roleLabels.protected} (protected party) benefits from positions closer to 10
- The ${roleLabels.providing} (providing party) benefits from positions closer to 1
- Position 5 represents a balanced, market-standard position

${userPartyName} is the ${userRoleLabel}. ${otherPartyName} is the ${otherRoleLabel}.
Use these role labels naturally in your responses (e.g. "as the ${userRoleLabel}, you..." or "the ${otherRoleLabel} may want...").
`
    : `
No specific contract type has been set. Use the role labels "${userRoleLabel}" and "${otherRoleLabel}" in your responses.
Positions closer to 10 favour the protected party; positions closer to 1 favour the providing party.
`
}

## CRITICAL RULE: POSITION ACCURACY

- Positions are on a 1-10 scale where 1 = most flexibility for ${roleLabels.providing}, 10 = most protection for ${roleLabels.protected}
- NEVER guess or interpolate what a position number means in practical terms
- ONLY state the practical meaning (e.g., '45 days', '120% of fees') if you have been given the POSITION LABELS
- If position labels are NOT provided, describe positions ONLY by their number and relative direction
  (e.g., "you moved from position 8 to 6, a concession toward the ${otherRoleLabel}")
- NEVER invent specific contract terms like day counts, percentages, or fee multiples from position numbers alone

## IMPORTANT TERMINOLOGY

- Leverage Balance (${ctx.leverage.leverageBalance || "N/A"}%) = how evenly matched the parties' overall negotiating power is
- Clause Alignment (${ctx.positions.alignmentPercentage}%) = the average agreement percentage across all contract clauses
- When the user asks about "alignment", they mean CLAUSE ALIGNMENT (what's on their screen)
- Never confuse these two metrics

## Your Core Identity

You are an expert mediator who:
- Guides parties through structured negotiation phases
- Maintains neutrality while ensuring fairness
- Focuses on creating mutually beneficial outcomes
- Combines legal expertise with practical business sense
- Makes complex contract negotiations accessible and efficient

## Language Rules — MANDATORY

1. NEVER use adversarial language ("versus", "against", "fighting", "battle")
   DO use "and", "alongside", "between", "working with"
2. NEVER say "aggressive" — use "strong", "firm", "priority"
3. NEVER refer to yourself as "the AI" or "AI-generated"
4. Use the correct role labels: "${userRoleLabel}" for the user, "${otherRoleLabel}" for the other party
5. Be confident — you ARE the expert

## Communication Style

- Be conversational and approachable, not overly formal
- Ask a maximum of TWO questions per response
- Provide clear explanations of legal concepts when needed
- Write naturally without excessive formatting tags

${
  ctx.mode.isTraining
    ? `
## TRAINING MODE ACTIVE
This is a training session. The user is practicing negotiation.
Opponent type: ${ctx.mode.trainingOpponentType || "balanced"}
${ctx.mode.opponentPersonality || ""}
Provide constructive feedback on their approach.
`
    : ""
}`;

// ============================================================================
// SECTION: FORMAT CLAUSE GAPS WITH POSITION LABELS
// ============================================================================

function formatClauseGap(c) {
  const userPos = isCustomerViewer ? c.customer_position : c.provider_position;
  const otherPos = isCustomerViewer ? c.provider_position : c.customer_position;
  const governs = getClauseGoverns(c.clause_name);

  let labelInfo = "";
  if (c.position_1_label || c.position_5_label || c.position_10_label) {
    labelInfo = `\n  Position scale: ${c.position_1_label || "?"} (1/${roleLabels.providing}-favourable) → ${c.position_5_label || "?"} (5/balanced) → ${c.position_10_label || "?"} (10/${roleLabels.protected}-favourable)`;

    const userMeaning = isCustomerViewer
      ? c.customer_position_meaning
      : c.provider_position_meaning;
    const otherMeaning = isCustomerViewer
      ? c.provider_position_meaning
      : c.customer_position_meaning;
    if (userMeaning)
      labelInfo += `\n  Your position (${userRoleLabel}) means approximately: ${userMeaning}`;
    if (otherMeaning)
      labelInfo += `\n  ${otherPartyName}'s position (${otherRoleLabel}) means approximately: ${otherMeaning}`;
  }

  return `- ${c.clause_name} (governs ${governs}): gap of ${parseFloat(c.gap_size).toFixed(1)}\n  Your position: ${userPos}/10, ${otherPartyName}'s position: ${otherPos}/10${labelInfo}`;
}

// ============================================================================
// SECTION: FORMAT CONTEXT SECTIONS
// ============================================================================

let biggestGapsText = "";
if (ctx.positions.biggestGaps && ctx.positions.biggestGaps.length > 0) {
  biggestGapsText = ctx.positions.biggestGaps
    .slice(0, 5)
    .map((g) => formatClauseGap(g))
    .join("\n");
}

let recentMovesText = "";
if (ctx.recentHistory.lastMoves && ctx.recentHistory.lastMoves.length > 0) {
  recentMovesText = ctx.recentHistory.lastMoves
    .slice(0, 3)
    .map((m) => {
      const isUserMove =
        (isCustomerViewer && m.partyRole === "customer") ||
        (!isCustomerViewer && m.partyRole === "provider");
      const moverName = isUserMove ? "You" : otherPartyName;
      const moverRole = isUserMove ? userRoleLabel : otherRoleLabel;

      let moveText = `- ${moverName} (${moverRole}) moved ${m.clauseName} from position ${m.fromPosition} to ${m.toPosition}`;

      if (m.position_1_label || m.position_5_label || m.position_10_label) {
        const fromMeaning = getPositionLabel(
          m.fromPosition,
          m.position_1_label,
          m.position_5_label,
          m.position_10_label,
        );
        const toMeaning = getPositionLabel(
          m.toPosition,
          m.position_1_label,
          m.position_5_label,
          m.position_10_label,
        );
        if (fromMeaning) moveText += `\n  From: approximately ${fromMeaning}`;
        if (toMeaning) moveText += `\n  To: approximately ${toMeaning}`;
      }

      return moveText;
    })
    .join("\n");
}

let recentChatText = "";
if (
  ctx.recentHistory.recentChatMessages &&
  ctx.recentHistory.recentChatMessages.length > 0
) {
  recentChatText = ctx.recentHistory.recentChatMessages
    .slice(0, 5)
    .reverse()
    .map(
      (msg) =>
        `${msg.senderRole === "clarence" ? "CLARENCE" : msg.senderRole === ctx.viewer.role ? "YOU" : otherPartyName.toUpperCase()}: ${msg.messageText.substring(0, 200)}${msg.messageText.length > 200 ? "..." : ""}`,
    )
    .join("\n\n");
}

let playbookText = "";
if (ctx.playbook && ctx.playbook.hasPlaybook) {
  playbookText = `\n=== PLAYBOOK GUIDANCE ===\n${ctx.viewer.company} has an active negotiation playbook: "${ctx.playbook.playbookName}"\nTotal rules: ${ctx.playbook.totalRules || 0}\nConsider their company policies when advising.\n`;
  if (ctx.playbook.activeAlerts && ctx.playbook.activeAlerts.length > 0) {
    playbookText += `\nACTIVE ALERTS:\n`;
    ctx.playbook.activeAlerts.forEach((alert) => {
      playbookText += `- [${alert.severity.toUpperCase()}] ${alert.alertTitle}\n`;
    });
  }
}

let strategicText = "";
if (
  ctx.viewer.role === "customer" &&
  ctx.strategicInsights.customerPriorities
) {
  strategicText = `\n=== YOUR PRIORITIES (Confidential to ${userRoleLabel}) ===\n`;
  if (ctx.strategicInsights.customerPriorities) {
    strategicText += `Priorities: ${JSON.stringify(ctx.strategicInsights.customerPriorities)}\n`;
  }
  if (ctx.strategicInsights.customerRedLines) {
    strategicText += `Red Lines: ${JSON.stringify(ctx.strategicInsights.customerRedLines)}\n`;
  }
} else if (
  ctx.viewer.role === "provider" &&
  ctx.strategicInsights.providerPriorities
) {
  strategicText = `\n=== YOUR PRIORITIES (Confidential to ${userRoleLabel}) ===\n`;
